const localHomeApp = new smarthome.App('1.0.0');

localHomeApp.onIdentify((request) => {
  const device = request.inputs[0].payload.device;
  console.log('Discovered local device:', device.id);

  // Return identifying information to match with cloud sync device list
  return {
    intent: smarthome.Intents.IDENTIFY,
    requestId: request.requestId,
    payload: {
      device: {
        id: device.id,
        verificationId: device.id
      }
    }
  };
});

localHomeApp.onExecute((request) => {
  const command = request.inputs[0].payload.commands[0];
  const execution = command.execution[0];

  // Construct local HTTP or UDP request packet
  const payload = JSON.stringify({ power: execution.params.on });
  const localCommand = new smarthome.DataFlow.HttpRequestData();
  localCommand.method = smarthome.DataFlow.HttpMethod.POST;
  localCommand.path = '/control';
  localCommand.data = payload;

  return localHomeApp.getDeviceManager()
    .send(localCommand)
    .then(() => ({
      intent: smarthome.Intents.EXECUTE,
      requestId: request.requestId,
      payload: { commands: [{ ids: [command.devices[0].id], status: 'SUCCESS' }] }
    }));
});
